// Concept: track pointerdown near left edge + pointermove right + distance threshold
// Coordinate with browser back-swipe (don't override system gesture)
import { useEffect } from 'react';
import { useRouter } from 'next/navigation';

export function useEdgeSwipeBack(enabled: boolean) {
  const router = useRouter();

  useEffect(() => {
    if (!enabled) return;
    let startX = 0;
    let active = false;

    const onPointerDown = (e: PointerEvent) => {
      if (e.pointerType !== 'touch') return;
      if (e.clientX > 30) return; // Only edge
      startX = e.clientX;
      active = true;
    };

    const onPointerUp = (e: PointerEvent) => {
      if (!active) return;
      const dx = e.clientX - startX;
      if (dx > 100) router.back();
      active = false;
    };

    document.addEventListener('pointerdown', onPointerDown, { passive: true });
    document.addEventListener('pointerup', onPointerUp);
    return () => {
      document.removeEventListener('pointerdown', onPointerDown);
      document.removeEventListener('pointerup', onPointerUp);
    };
  }, [enabled, router]);
}

