import { useState, useEffect } from 'react';

export function ValidatedField({ value, onChange, validate, label }: { value: string; onChange: (v: string) => void; validate: (v: string) => string | null; label: string }) {
  const [error, setError] = useState<string | null>(null);
  const [touched, setTouched] = useState(false);

  useEffect(() => {
    if (!touched) return;
    const t = setTimeout(() => setError(validate(value)), 500);
    return () => clearTimeout(t);
  }, [value, validate, touched]);

  return (
    <label>
      <span className="text-sm font-medium">{label}</span>
      <input
        type="text"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onBlur={() => setTouched(true)}
        aria-invalid={Boolean(error)}
        aria-describedby="error"
        className={`mt-1 block w-full min-h-11 rounded border px-3 text-base aria-invalid:border-red-500`}
      />
      <p id="error" role={error ? 'alert' : undefined} className="min-h-[1.25rem] mt-1 text-sm text-red-600">{error}</p>
    </label>
  );
}

